const err = $input.first().json;
const workflow_name = err.workflow && err.workflow.name ? err.workflow.name : 'unknown';
const node_name = err.execution && err.execution.error && err.execution.error.node ? err.execution.error.node.name : '';
const error_message = err.execution && err.execution.error && err.execution.error.message ? err.execution.error.message : JSON.stringify(err.execution ? err.execution.error : {});

// Classify error type for triage
const msg = (error_message || '').toLowerCase();
let error_category = 'other';
if (msg.includes('rate limit') || msg.includes('429') || msg.includes('too many')) error_category = 'rate_limit';
else if (msg.includes('auth') || msg.includes('401') || msg.includes('403') || msg.includes('unauthorized') || msg.includes('forbidden')) error_category = 'auth';
else if (msg.includes('timeout') || msg.includes('etimedout') || msg.includes('econnreset')) error_category = 'timeout';
else if (msg.includes('parse') || msg.includes('json') || msg.includes('syntax')) error_category = 'parse';
else if (msg.includes('not found') || msg.includes('404')) error_category = 'not_found';
else if (msg.includes('invalid') || msg.includes('validation')) error_category = 'validation';

return [{
  json: {
    workflow_name,
    node_name,
    error_message,
    error_category,
    file_id: null
  }
}];

const file = $input.first().json;
const name = (file.name || '').toLowerCase();

// Document type classification
let document_type = 'General';
if (name.includes('contract') || name.includes('agreement') || name.includes('nda')) document_type = 'Contract';
else if (name.includes('policy')) document_type = 'Policy';
else if (name.includes('manual') || name.includes('handbook')) document_type = 'Manual';
else if (name.includes('compliance') || name.includes('sop') || name.includes('audit')) document_type = 'Compliance';
else if (name.includes('benefit') || name.includes('leave') || name.includes('insurance')) document_type = 'Benefits';

// Use Google Drive's pre-computed hash — no crypto module needed
// Fallback chain: sha256 → md5 → fileId+modifiedTime as pseudo-hash
const file_hash = file.sha256Checksum 
  || file.md5Checksum 
  || (file.id + '_' + file.modifiedTime).replace(/[^a-zA-Z0-9]/g, '');

return [{
  json: {
    file_id: file.id,
    file_name: file.name,
    mime_type: file.mimeType,
    document_type,
    file_hash,
    modified_time: file.modifiedTime,
    upload_date: new Date().toISOString(),
    source_url: file.webViewLink || 'https://drive.google.com/file/d/' + file.id + '/view'
  },
  binary: $input.first().binary
}];

