const meta = $('Extract Metadata + Hash').first().json;
const existing = $input.first().json;

// If hash matches and status is 'indexed', skip entirely
const needsProcessing = !(existing && existing.file_hash === meta.file_hash && existing.status === 'indexed');

return [{
  json: {
    ...meta,
    needs_processing: needsProcessing,
    existing_status: existing ? existing.status : 'new'
  },
  binary: $('Extract Metadata + Hash').first().binary
}];

const input = $input.first().json;

// Handle multiple possible request structures
let query = '';
if (input.body && typeof input.body === 'object' && input.body.query) {
  query = input.body.query;
} else if (input.query) {
  query = input.query;
} else if (input.params && input.params.query) {
  query = input.params.query;
} else if (typeof input.body === 'string') {
  // Sometimes body is sent as a JSON string
  try {
    const parsed = JSON.parse(input.body);
    query = parsed.query || '';
  } catch (e) {
    query = input.body;
  }
}

query = (query || '').toString().trim();
if (!query) {
  throw new Error('Missing query field in request body. Received: ' + JSON.stringify(input).substring(0, 200));
}

// Normalize for cache key (lowercase, collapse whitespace)
const normalized = query.toLowerCase().replace(/\s+/g, ' ').trim();

// Simple deterministic hash using string manipulation (no crypto module)
function simpleHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return (hash >>> 0).toString(16).padStart(8, '0') + 
         Buffer.from(str).toString('base64').replace(/[^a-zA-Z0-9]/g, '').substring(0, 16);
}

const query_hash = simpleHash(normalized).substring(0, 32);

return [{ json: { query, query_hash, t_start: Date.now() } }];

const raw = $input.first().json.response_json;
const cached = typeof raw === 'string' ? JSON.parse(raw) : raw;
const t_start = $('Parse + Hash').first().json.t_start;

return [{
  json: {
    ...cached,
    cache_hit: true,
    latency_ms: Date.now() - t_start,
    _log: {
      query: $('Parse + Hash').first().json.query,
      query_hash: $('Parse + Hash').first().json.query_hash,
      chunks_retrieved: 0,
      doc_types_searched: []
    }
  }
}];

const raw = $input.first().json.message.content.trim();
let docTypes;
try {
  docTypes = JSON.parse(raw);
  if (!Array.isArray(docTypes) || docTypes.length === 0) throw new Error('empty');
} catch(e) {
  docTypes = ['Policy','Contract','Manual','Compliance','Benefits','General'];
}
const valid = ['Policy','Contract','Manual','Compliance','Benefits','General'];
docTypes = docTypes.filter(t => valid.includes(t));
if (!docTypes.length) docTypes = valid;

return [{
  json: {
    query: $('Parse + Hash').first().json.query,
    query_hash: $('Parse + Hash').first().json.query_hash,
    t_start: $('Parse + Hash').first().json.t_start,
    doc_types: docTypes
  }
}];

const embedding = $input.first().json.data[0].embedding;
const ctx = $('Parse Doc Types').first().json;
return [{
  json: {
    ...ctx,
    vector: embedding,
    filter: { document_type: { '$in': ctx.doc_types } }
  }
}];

// Deduplicate adjacent chunks from the same file, keep top N candidates
const resp = $input.first().json;
const matches = resp.matches || [];

// Group by file_id + chunk_index proximity (collapse consecutive chunks)
const seen = new Set();
const unique = [];
for (const m of matches) {
  const fileId = m.metadata?.file_id || m.id;
  const chunkIdx = m.metadata?.loc?.lines?.from || 0;
  const key = `${fileId}_${Math.floor(chunkIdx / 2)}`;
  if (seen.has(key)) continue;
  seen.add(key);
  unique.push({
    id: m.id,
    score: m.score || 0,
    content: m.metadata?.text || m.metadata?.pageContent || '',
    file_name: m.metadata?.file_name || 'unknown',
    document_type: m.metadata?.document_type || 'General',
    source_url: m.metadata?.source_url || ''
  });
}

const ctx = $('Build Pinecone Query').first().json;
return [{
  json: {
    query: ctx.query,
    query_hash: ctx.query_hash,
    t_start: ctx.t_start,
    doc_types: ctx.doc_types,
    candidates: unique.slice(0, 10)  // top 10 for reranking
  }
}];

const ctx = $('Deduplicate Chunks').first().json;
const rerankRaw = $input.first().json?.message?.content || '[]';

let scores;
try {
  scores = JSON.parse(rerankRaw.trim());
  if (!Array.isArray(scores)) throw new Error('not array');
} catch(e) {
  // Fallback: use original Pinecone order
  scores = ctx.candidates.map((_, i) => 10 - i);
}

// Attach rerank scores and re-sort
const scored = ctx.candidates.map((c, i) => ({
  ...c,
  rerank_score: scores[i] !== undefined ? scores[i] : 0
})).sort((a, b) => b.rerank_score - a.rerank_score);

// Hardcoded topN = 5 (replaces broken Set Config1 reference)
const topN = 5;
const top = scored.slice(0, topN);

// Confidence based on top rerank score (0-10 scale)
const topScore = top[0]?.rerank_score || 0;
let confidence = 'Low';
if (topScore >= 8) confidence = 'High';
else if (topScore >= 5) confidence = 'Medium';

const contextBlock = top.map((c, i) =>
  `[SOURCE ${i+1}: ${c.file_name} | Type: ${c.document_type} | Relevance: ${c.rerank_score}/10]\n${c.content}\n---`
).join('\n\n');

const sources = [...new Set(top.map(c => c.file_name))];

return [{
  json: {
    query: ctx.query,
    query_hash: ctx.query_hash,
    t_start: ctx.t_start,
    doc_types: ctx.doc_types,
    context: contextBlock || '(no relevant documents found)',
    sources,
    confidence,
    chunks_retrieved: top.length,
    low_confidence: confidence === 'Low'
  }
}];

