const raw = $input.first().json.message.content;
const ctx = $('Build Context').first().json;

let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch(e) {
  parsed = {
    answer: 'I could not generate a valid response. Please try again.',
    sources: [],
    confidence: 'Low',
    answer_found: false,
    follow_up_suggestions: []
  };
}

// Citation enforcement: positive answer MUST cite sources
if (parsed.answer_found && (!parsed.sources || parsed.sources.length === 0)) {
  parsed = {
    answer: 'This information is not available in the current HR documents. Please contact the HR department.',
    sources: [],
    confidence: 'Low',
    answer_found: false,
    follow_up_suggestions: []
  };
}

const response = {
  answer: parsed.answer,
  sources: parsed.sources || [],
  confidence: parsed.confidence || ctx.confidence,
  answer_found: parsed.answer_found !== false,
  follow_up_suggestions: parsed.follow_up_suggestions || [],
  cache_hit: false,
  latency_ms: Date.now() - ctx.t_start
};

return [{
  json: {
    ...response,
    _log: {
      query: ctx.query,
      query_hash: ctx.query_hash,
      chunks_retrieved: ctx.chunks_retrieved,
      doc_types_searched: ctx.doc_types
    }
  }
}];

